class WithoutSlots:
    def __init__(self, x, y):
        self.x = x
        self.y = y

class WithSlots:
    __slots__ = ['x', 'y']
    def __init__(self, x, y):
        self.x = x
        self.y = y

obj1 = WithoutSlots(1, 2)
obj2 = WithSlots(1, 2)

print("without slots has __dict__:", hasattr(obj1, '__dict__'))
print("with slots has __dict__:", hasattr(obj2, '__dict__'))
print("obj2.x:", obj2.x, "obj2.y:", obj2.y)

try:
    obj2.z = 3
except AttributeError as e:
    print("slots error:", e)

exercises.solution:
class Regular:
    def __init__(self, name, age):
        self.name = name
        self.age = age

class Optimized:
    __slots__ = ['name', 'age']
    def __init__(self, name, age):
        self.name = name
        self.age = age

r = Regular("Alice", 30)
o = Optimized("Bob", 25)

r.email = "alice@example.com"
print(f"{r.name}, {r.age}, {r.email}")
print("Regular __dict__:", r.__dict__)

print(f"{o.name}, {o.age}")
print("Has __dict__:", hasattr(o, '__dict__'))

try:
    o.email = "bob@example.com"
except AttributeError as e:
    print("Cannot add attribute:", e)
